import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"圣诞老人的回信","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/圣诞老人的回信.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/圣诞老人的回信.md"}'),p={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/圣诞老人的回信.md"};function d(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"圣诞老人的回信",tabindex:"-1"},[s("圣诞老人的回信 "),e("a",{class:"header-anchor",href:"#圣诞老人的回信","aria-label":'Permalink to "圣诞老人的回信"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="圣诞老人的回信-1" tabindex="-1">圣诞老人的回信 <a class="header-anchor" href="#圣诞老人的回信-1" aria-label="Permalink to &quot;圣诞老人的回信&quot;">​</a></h1><p>圣诞老人的回信<br> 魔幻本质<br> 奇物<br> 10分</p><p>一封泛黄的信纸，边缘有手剪的雪花纹样，收信人栏位空着，但寄信人处用歪歪扭扭的笔迹写着“北极·圣诞老人（寄）”。</p><p>“我亲爱的朋友，非常抱歉，因为今年的圣诞礼物实在太多了，所以我们不小心把你的礼物寄错了地方……” 剩下的字迹就像被雪花遮掩一样模糊不清。</p><p>每场影片一次，你可以在信笺上写下一件你许愿物品的名字，这件物品的体积不能过大，且物品的价值不能超过10分等价的资金。此后你进行一次机运骰，如果你获得了6或更高的结果，那么在接下来的1小时内，你会在口袋、抽屉或马路上偶然捡到这件记错了地址的礼物。否则，你在第二年的这个时候才能找到这件物品，前提是你还在影片内。</p><p>如果你在收信人处写下了一个名字，那么这封信件会缓缓变成透明，直至消失，并在第二天的早晨送到你写下名字的那个人手里，收信栏再次恢复空白。</p><p>*永远的等待……*</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
